## ЗАДАЧА 3 — Обработка 100K HTTP-запросов concurrently с ограничением 100 соединений

```typescript
import { setTimeout } from 'timers/promises';

class RequestLimiter {
    private activeRequests = 0;
    private queue: Array<() => Promise<any>> = [];
    private maxConcurrent: number;

    constructor(maxConcurrent: number) {
        this.maxConcurrent = maxConcurrent;
    }

    async add<T>(requestFn: () => Promise<T>): Promise<T> {
        return new Promise((resolve, reject) => {
            const wrappedRequest = async () => {
                try {
                    const result = await requestFn();
                    resolve(result);
                } catch (error) {
                    reject(error);
                } finally {
                    this.activeRequests--;
                    this.processQueue();
                }
            };

            if (this.activeRequests < this.maxConcurrent) {
                this.activeRequests++;
                wrappedRequest();
            } else {
                this.queue.push(wrappedRequest);
            }
        });
    }

    private processQueue() {
        while (this.queue.length > 0 && this.activeRequests < this.maxConcurrent) {
            this.activeRequests++;
            const nextRequest = this.queue.shift()!;
            nextRequest();
        }
    }
}

async function process100kRequests(requests: Array<() => Promise<any>>) {
    const limiter = new RequestLimiter(100);
    const results = new Array(requests.length);
    const errors: Array<Error> = [];

    // Используем Promise.all для параллельной обработки
    const processingPromises = requests.map((requestFn, index) => 
        limiter.add(async () => {
            try {
                // Экспоненциальная задержка при повторных попытках
                let retryCount = 0;
                const maxRetries = 3;

                while (retryCount < maxRetries) {
                    try {
                        const result = await requestFn();
                        return result;
                    } catch (error) {
                        retryCount++;
                        if (retryCount >= maxRetries) throw error;
                        await setTimeout(Math.pow(2, retryCount) * 100); // Экспоненциальная задержка
                    }
                }
            } catch (error) {
                errors.push(error as Error);
                throw error;
            }
        }).then(result => {
            results[index] = result;
        })
    );

    await Promise.all(processingPromises);

    return { results, errors };
}
```

**Big O:** O(n) — время, где n - количество запросов, O(m) — пространство, где m - максимальное количество одновременных запросов

**Объяснение:**
- Класс `RequestLimiter` управляет количеством одновременных запросов
- Очередь запросов гарантирует обработку в порядке поступления
- Экспоненциальная задержка при повторных попытках
- Параллельная обработка с помощью `Promise.all`

**Оптимизации:**
- Фиксированный лимит соединений предотвращает истощение ресурсов
- Очередная обработка запросов без блокировки основного потока
- Минимизация аллокаций через переиспользование массивов
- Обработка ошибок с перехватом и повторными попытками

